from microcoapy import CoAPServer, Resource

class TemperatureResource(Resource):
    def __init__(self):
        super().__init__("sensors/temp")
        self.temperature = 25.0  # Default temperature value

    def get(self, request):
        return str(self.temperature)

    def put(self, request):
        try:
            self.temperature = float(request.payload.decode())
            return "Temperature set to {}".format(self.temperature)
        except ValueError:
            return "Invalid value", 400

class LightActuatorResource(Resource):
    def __init__(self):
        super().__init__("actuators/light")
        self.light_status = "off"  # Default light status

    def get(self, request):
        return self.light_status

    def put(self, request):
        if request.payload.decode() in ["on", "off"]:
            self.light_status = request.payload.decode()
            return "Light turned {}".format(self.light_status)
        else:
            return "Invalid status", 400

server = CoAPServer()
server.add_resource(TemperatureResource())
server.add_resource(LightActuatorResource())

if __name__ == "__main__":
    server.run()